#include<bits/stdc++.h>
using namespace std;
int a[51][51],b[51],dp[51][4101];
const int mod=1e8;
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&a[i][j]);
            b[i]=b[i]*2+a[i][j];
        }
    }
    dp[0][0]=1;
    for(int i=1;i<=n;i++)
    {
        for(int j=0;j<(1<<m);j++)
        {
            if((!(j&((j<<1)|(j>>1)))&&(j|b[i])==b[i]))
            {
                for(int k=0;k<(1<<m);k++)
                {
                    if(!(j&k))
                    {
                        dp[i][j]+=dp[i-1][k];
                        dp[i][j]%=mod;
                    }
                }
            }
        }
    }
    int ans=0;
    for(int i=0;i<(1<<m);i++)
    {
        ans+=dp[n][i];
        ans%=mod;
    }
    printf("%d",ans);
    return 0;
}
